// Initialize workflow context and generate unique request ID
const requestId = `research_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
const timestamp = new Date().toISOString();

const input = $input.first().json.body;

return [{
  json: {
    request_id: requestId,
    timestamp: timestamp,
    text_prompt: input.text_prompt || null,
    images: input.images || [],
    project_context: input.project_context || "General Research",
    has_text: !!input.text_prompt,
    has_images: Array.isArray(input.images) && input.images.length > 0,
    input_type: input.text_prompt && input.images?.length > 0 ? "hybrid" : 
                input.text_prompt ? "text_only" : "image_only"
  }
}];

// Parse ChatGPT JSON response and prepare for Pinterest API calls
const items = $input.all();
const parsed = [];

items.forEach(item => {
  try {
    let responseText = item.json.message?.content || item.json.text || JSON.stringify(item.json);

    // Strip markdown code blocks if present
    responseText = responseText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

    const queryData = JSON.parse(responseText);

    // Create array of all queries to execute
    const allQueries = [
      { query: queryData.primary_query, type: 'primary', strategy: queryData.search_strategy }
    ];

    if (Array.isArray(queryData.alternative_queries)) {
      queryData.alternative_queries.forEach((altQuery, idx) => {
        allQueries.push({ query: altQuery, type: `alternative_${idx + 1}`, strategy: queryData.search_strategy });
      });
    }

    // Pass through context from earlier nodes
    const context = item.json.request_id ? item.json : $('Code — Initialize Context').first().json;

    parsed.push({
      json: {
        ...context,
        queries: allQueries,
        total_queries: allQueries.length,
        visual_analysis: queryData.visual_analysis || null
      }
    });

  } catch (error) {
    // Log parsing error but continue workflow
    parsed.push({
      json: {
        error: 'JSON parsing failed',
        raw_response: item.json,
        error_message: error.message
      }
    });
  }
});

return parsed;

// Log API failure to Google Sheets error log
const item = $input.first().json;

const errorLog = {
  timestamp: new Date().toISOString(),
  request_id: item.request_id || 'unknown',
  error_type: 'Pinterest API Failure',
  status_code: item.statusCode || 'N/A',
  error_message: item.body?.message || item.error || 'Unknown error',
  query_attempted: item.queries?.query || 'N/A',
  full_response: JSON.stringify(item, null, 2)
};

return [{ json: errorLog }];

// Normalize Pinterest API response into clean, structured format
const item = $input.first().json;
const responseBody = item.body;
const pins = responseBody.items || [];
const context = item; // Contains request_id, queries, etc.

const normalized = [];

pins.forEach((pin, index) => {
  // Calculate relevance score
  const queryTerms = (context.queries?.query || '').toLowerCase().split(' ');
  let score = 0;

  // Title match (weight: 3)
  const title = (pin.title || '').toLowerCase();
  queryTerms.forEach(term => {
    if (title.includes(term)) score += 3;
  });

  // Description match (weight: 2)
  const description = (pin.description || '').toLowerCase();
  queryTerms.forEach(term => {
    if (description.includes(term)) score += 2;
  });

  // Recency bonus (pins from last 6 months get +5)
  if (pin.created_at) {
    const pinAge = Date.now() - new Date(pin.created_at).getTime();
    const sixMonths = 15552000000; // 180 days in ms
    if (pinAge < sixMonths) score += 5;
  }

  // Image quality indicator (high-res images get +2)
  const imageWidth = pin.media?.images?.orig?.width || 0;
  if (imageWidth > 1000) score += 2;

  // Board follower count bonus (popular boards get +1)
  const boardFollowers = pin.board?.follower_count || 0;
  if (boardFollowers > 1000) score += 1;

  normalized.push({
    request_id: context.request_id,
    search_query: context.queries?.query,
    query_type: context.queries?.type,
    rank: index + 1,
    relevance_score: score,
    pin_id: pin.id,
    title: pin.title || pin.description?.substring(0, 100) || 'Untitled',
    description: pin.description || '',
    image_url: pin.media?.images?.orig?.url || pin.media?.images?.['1200x']?.url || '',
    thumbnail_url: pin.media?.images?.['400x300']?.url || pin.media?.images?.['236x']?.url || '',
    board_name: pin.board?.name || 'Unknown',
    board_id: pin.board?.id || '',
    creator_username: pin.pinner?.username || 'Unknown',
    creator_profile: pin.pinner?.profile_url || '',
    external_link: pin.link || '',
    created_at: pin.created_at || '',
    pinterest_url: `https://pinterest.com/pin/${pin.id}/`,
    repin_count: pin.repin_count || 0,
    image_width: imageWidth,
    image_height: pin.media?.images?.orig?.height || 0,
    dominant_color: pin.dominant_color || '',
    retrieved_at: new Date().toISOString()
  });
});

return normalized.map(item => ({ json: item }));

// Deduplicate pins by pin_id and sort by relevance score
const items = $input.all();
const seenPinIds = new Set();
const deduped = [];

items.forEach(item => {
  const pinId = item.json.pin_id;
  if (!seenPinIds.has(pinId)) {
    seenPinIds.add(pinId);
    deduped.push(item);
  }
});

// Sort by relevance score (descending)
deduped.sort((a, b) => b.json.relevance_score - a.json.relevance_score);

// Re-assign rank after deduplication and sorting
deduped.forEach((item, index) => {
  item.json.final_rank = index + 1;
});

return deduped;

// Prepare webhook response with top 10 results
const allResults = $input.all();
const context = $('Code — Initialize Context').first().json;
const spreadsheet = $('Google Sheets — Create New Spreadsheet').first().json;

const top10 = allResults.slice(0, 10).map(item => ({
  rank: item.json.final_rank,
  title: item.json.title,
  image_url: item.json.image_url,
  pinterest_url: item.json.pinterest_url,
  relevance_score: item.json.relevance_score,
  board_name: item.json.board_name,
  creator: item.json.creator_username
}));

const response = {
  status: 'success',
  request_id: context.request_id,
  query_used: allResults[0]?.json.search_query || 'Multiple queries executed',
  total_results: allResults.length,
  unique_pins: allResults.length,
  top_results: top10,
  sheet_url: spreadsheet.spreadsheetUrl,
  sheet_id: spreadsheet.spreadsheetId,
  processing_time_ms: Date.now() - new Date(context.timestamp).getTime(),
  input_type: context.input_type,
  project_context: context.project_context
};

return [{ json: response }];
